#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n\n\"\"\"\n╔═══════════════════════════════════════════════════════════╗\n║     🚀 MANOS Google Drive Uploader & Link Generator       ║\n║                                                           ║\n║         صُنعت في العراق العظيم 🇮🇶                        ║\n║      على يد: أمير الحشداوي (fhd3dail-pixel)              ║\n║                                                           ║\n║  أداة رفع APK على Google Drive وإنشاء رابط تحميل        ║\n╚═══════════════════════════════════════════════════════════╝\n\"\"\"\n\nimport os\nimport pickle\nfrom google.auth.transport.requests import Request\nfrom google.oauth2.credentials import Credentials\nfrom google_auth_oauthlib.flow import InstalledAppFlow\nfrom google.colab import auth\nfrom googleapiclient.discovery import build\nfrom googleapiclient.http import MediaFileUpload\nimport json\n\nclass MANOSGoogleDriveUploader:\n    \"\"\"أداة رفع APK على Google Drive\"\"\"\n    \n    def __init__(self):\n        self.SCOPES = ['https://www.googleapis.com/auth/drive']\n        self.service = None\n    \n    def authenticate(self):\n        \"\"\"المصادقة مع Google Drive\"\"\"\n        print(\"\\n🔐 جاري المصادقة مع Google Drive...\")\n        try:\n            auth.authenticate_user()\n            self.service = build('drive', 'v3')\n            print(\"✅ تمت المصادقة بنجاح!\")\n            return True\n        except Exception as e:\n            print(f\"❌ خطأ في المصادقة: {e}\")\n            return False\n    \n    def create_folder(self, folder_name=\"MANOS Downloads\"):\n        \"\"\"إنشاء مجلد على Google Drive\"\"\"\n        print(f\"\\n📁 إنشاء مجلد: {folder_name}...\")\n        try:\n            file_metadata = {\n                'name': folder_name,\n                'mimeType': 'application/vnd.google-apps.folder'\n            }\n            folder = self.service.files().create(\n                body=file_metadata,\n                fields='id'\n            ).execute()\n            folder_id = folder.get('id')\n            print(f\"✅ تم إنشاء المجلد: {folder_id}\")\n            return folder_id\n        except Exception as e:\n            print(f\"❌ خطأ: {e}\")\n            return None\n    \n    def upload_file(self, file_path, folder_id=None):\n        \"\"\"رفع ملف APK على Google Drive\"\"\"\n        if not os.path.exists(file_path):\n            print(f\"❌ الملف {file_path} غير موجود!\")\n            return None\n        \n        print(f\"\\n📤 جاري رفع الملف: {file_path}...\")\n        print(f\"   الحجم: {os.path.getsize(file_path) / (1024*1024):.2f} MB\")\n        \n        try:\n            file_name = os.path.basename(file_path)\n            file_metadata = {'name': file_name}\n            \n            if folder_id:\n                file_metadata['parents'] = [folder_id]\n            \n            media = MediaFileUpload(\n                file_path,\n                mimetype='application/vnd.android.package-archive',\n                resumable=True\n            )\n            \n            file = self.service.files().create(\n                body=file_metadata,\n                media_body=media,\n                fields='id, webViewLink, name'\n            ).execute()\n            \n            print(f\"✅ تم الرفع بنجاح!\")\n            return file\n        except Exception as e:\n            print(f\"❌ خطأ في الرفع: {e}\")\n            return None\n    \n    def make_file_public(self, file_id):\n        \"\"\"جعل الملف متاح للجميع\"\"\"\n        print(f\"\\n🌐 جاري جعل الملف متاح للجميع...\")\n        try:\n            self.service.permissions().create(\n                fileId=file_id,\n                body={'type': 'anyone', 'role': 'reader'}\n            ).execute()\n            print(\"✅ الملف متاح للجميع الآن!\")\n            return True\n        except Exception as e:\n            print(f\"❌ خطأ: {e}\")\n            return False\n    \n    def get_download_link(self, file_id):\n        \"\"\"الحصول على رابط التحميل المباشر\"\"\"\n        # رابط التحميل المباشر من Google Drive\n        download_link = f\"https://drive.google.com/uc?export=download&id={file_id}\"\n        return download_link\n    \n    def upload_and_share(self, apk_path, folder_name=\"MANOS Downloads\"):\n        \"\"\"رفع ومشاركة الملف\"\"\"\n        print(\"\\n\" + \"=\"*60)\n        print(\"🚀 MANOS Google Drive Uploader\")\n        print(\"=\"*60)\n        \n        # المصادقة\n        if not self.authenticate():\n            return None\n        \n        # إنشاء مجلد\n        folder_id = self.create_folder(folder_name)\n        \n        # رفع الملف\n        file_info = self.upload_file(apk_path, folder_id)\n        \n        if not file_info:\n            return None\n        \n        file_id = file_info.get('id')\n        file_name = file_info.get('name')\n        web_link = file_info.get('webViewLink')\n        \n        # جعل الملف عام\n        self.make_file_public(file_id)\n        \n        # الحصول على رابط التحميل\n        download_link = self.get_download_link(file_id)\n        \n        # النتيجة النهائية\n        print(\"\\n\" + \"=\"*60)\n        print(\"✅ تم بنجاح!\")\n        print(\"=\"*60)\n        print(f\"\\n📱 اسم الملف: {file_name}\")\n        print(f\"\\n📎 رابط Google Drive:\")\n        print(f\"   {web_link}\")\n        print(f\"\\n⚡ رابط التحميل المباشر:\")\n        print(f\"   {download_link}\")\n        print(f\"\\n🔗 انسخ هذا الرابط وشاركه:\")\n        print(f\"   {download_link}\")\n        print(\"\\n\" + \"=\"*60)\n        print(\"🇮🇶 صُنعت في العراق العظيم\")\n        print(\"👤 على يد: أمير الحشداوي\\n\")\n        \n        return {\n            'file_id': file_id,\n            'file_name': file_name,\n            'web_link': web_link,\n            'download_link': download_link\n        }\n\ndef main():\n    \"\"\"البرنامج الرئيسي\"\"\"\n    print(\"\"\"\n    ╔════════════════════════════════════════════════════════════╗\n    ║                                                            ║\n    ║     🚀 MANOS Google Drive Uploader & Link Generator       ║\n    ║                                                            ║\n    ║         صُنعت في العراق العظيم 🇮🇶                        ║\n    ║      على يد: أمير الحشداوي (fhd3dail-pixel)              ║\n    ║                                                            ║\n    ║  أداة رفع APK على Google Drive وإنشاء رابط تحميل        ║\n    ║                                                            ║\n    ╚════════════════════════════════════════════════════════════╝\n    \"\"\")\n    \n    # طلب مسار الملف من المستخدم\n    apk_path = input(\"\\n📁 أدخل مسار ملف APK (أو اضغط Enter للبحث تلقائي): \").strip()\n    \n    if not apk_path:\n        # البحث التلقائي\n        print(\"\\n🔍 جاري البحث عن ملفات APK...\")\n        apk_files = []\n        for root, dirs, files in os.walk('.'):\n            for file in files:\n                if file.endswith('.apk'):\n                    apk_files.append(os.path.join(root, file))\n        \n        if apk_files:\n            print(f\"\\n✅ وجدت {len(apk_files)} ملف(ات):\")\n            for i, f in enumerate(apk_files, 1):\n                print(f\"   {i}. {f}\")\n            choice = input(\"\\nاختر ملف (رقم): \")\n            apk_path = apk_files[int(choice)-1]\n        else:\n            print(\"❌ لم أجد أي ملفات APK!\")\n            return\n    \n    # رفع الملف\n    uploader = MANOSGoogleDriveUploader()\n    result = uploader.upload_and_share(apk_path)\n    \n    if result:\n        # حفظ النتيجة في ملف\n        with open('upload_result.json', 'w') as f:\n            json.dump(result, f, indent=2, ensure_ascii=False)\n        print(\"\\n💾 تم حفظ النتيجة في: upload_result.json\")\n\nif __name__ == \"__main__\":\n    main()\n"